import React from 'react'
import './Post.css'
import {MoreVert} from "@mui/icons-material";

const PostContent = () => {
  return (
    <div className="content">
<div className="cwrapper">
    <div className="ctop">
    <div className="topleft">
    <img className="cpic" alt='profilepic' src='/assets/friends/friend1.jpg' />
    <span className="cusername">Britney Spears</span>
    <span className="cdate">10 mins ago</span>
    </div>
    <div className="topright"></div>

<MoreVert />
    </div>
    <div className="ccenter">
    <span className="ctext">Cutie</span>
    <img className="cimg" alt='postpic' src='/assets/friends/friend4.jpg' />
    </div>
    <div className="cbottom">
<div className="cbottomleft">
<img className="cicon" alt='iconpic' src='/assets/icons/heart.png' />
<img className="cicon" alt='iconpic' src='/assets/icons/like.png' />
<img className="cicon" alt='iconpic' src='/assets/icons/dislike.png' />
<span className="like">35 people</span>
<span className="dislike">2 people</span>
</div>
<div className="cbottomright"></div>
    </div>
</div>


    </div>
  )
}

export default PostContent


